12	// WorkFocusBead is one item in the operator-attention section.
13	type WorkFocusBead struct {
14		ID              string `json:"id"`
15		Title           string `json:"title"`
16		Reason          string `json:"reason,omitempty"`
17		SuggestedAction string `json:"suggested_action,omitempty"`
18	}
19	
20	// WorkFocusBlockedBead is one item in the blocked_or_planning section.
21	type WorkFocusBlockedBead struct {
22		ID          string `json:"id"`
23		Title       string `json:"title"`
24		BlockerKind string `json:"blocker_kind"`
25		Detail      string `json:"detail,omitempty"`
26	}
27	
28	// WorkFocusReadySummary is the ready-queue depth summary.
29	type WorkFocusReadySummary struct {
30		Count int    `json:"count"`
31		Depth string `json:"depth"` // "empty", "shallow", "moderate", "deep"
32	}
33	
34	// WorkFocusReport is the structured result of "ddx work focus".
35	type WorkFocusReport struct {
36		HumanRequired        []WorkFocusBead        `json:"human_required"`
37		BlockedOrPlanning    []WorkFocusBlockedBead `json:"blocked_or_planning"`
38		ReadySummary         WorkFocusReadySummary  `json:"ready_summary"`
39		WorkerRecommendation string                 `json:"worker_recommendation"`
40		Unknowns             []string               `json:"unknowns"`
41	}
42	
43	// workerReadyDepthLabel returns a human-readable depth label for the ready count.
44	func workerReadyDepthLabel(count int) string {
45		switch {
46		case count == 0:
47			return "empty"
48		case count <= 1:
49			return "shallow"
50		case count <= 3:
51			return "moderate"
52		default:
53			return "deep"
54		}
55	}
56	
57	// buildWorkFocusReport queries the store and returns a WorkFocusReport.
58	func buildWorkFocusReport(store *bead.Store) (WorkFocusReport, error) {
59		// Collect operator-attention beads (status=proposed, any dep state).
60		operatorAttentionBeads, err := store.ProposedOperatorAttention()
61		if err != nil {
62			return WorkFocusReport{}, fmt.Errorf("work focus: operator attention query: %w", err)
63		}
64	
65		// Build a set of operator-attention IDs so we can exclude them from blocked section.
66		operatorAttentionSet := make(map[string]bool, len(operatorAttentionBeads))
67		humanRequired := make([]WorkFocusBead, 0, len(operatorAttentionBeads))
68		for _, b := range operatorAttentionBeads {
69			operatorAttentionSet[b.ID] = true
70			meta := bead.GetNeedsHumanMeta(b)
71			item := WorkFocusBead{
72				ID:    b.ID,
73				Title: b.Title,
74			}
75			if meta.Reason != "" {
76				item.Reason = meta.Reason
77			} else if meta.Summary != "" {
78				item.Reason = meta.Summary
79			}
80			if meta.SuggestedAction != "" {
81				item.SuggestedAction = meta.SuggestedAction
82			}
83			humanRequired = append(humanRequired, item)
84		}
85	
86		// Collect all blocked beads; exclude operator-attention beads already captured above.
87		allBlocked, err := store.BlockedAll()
88		if err != nil {
89			return WorkFocusReport{}, fmt.Errorf("work focus: blocked query: %w", err)
90		}
91		var blockedOrPlanning []WorkFocusBlockedBead
92		for _, bb := range allBlocked {
93			if operatorAttentionSet[bb.ID] {
94				continue
95			}
96			item := WorkFocusBlockedBead{
97				ID:          bb.ID,
98				Title:       bb.Title,
99				BlockerKind: bb.Blocker.Kind,
100			}
101			switch bb.Blocker.Kind {
102			case bead.BlockerKindDependency:
103				if len(bb.Blocker.UnclosedDepIDs) > 0 {
104					item.Detail = "unclosed deps: " + strings.Join(bb.Blocker.UnclosedDepIDs, ", ")
105				}
106			case bead.BlockerKindRetryCooldown:
107				if bb.Blocker.NextEligibleAt != "" {
108					item.Detail = "retry after: " + bb.Blocker.NextEligibleAt
109				}
110			default:
111				if bb.Blocker.Reason != "" {
112					item.Detail = bb.Blocker.Reason
113				}
114			}
115			blockedOrPlanning = append(blockedOrPlanning, item)
116		}
117	
118		// Collect worker-ready depth.
119		readyBeads, err := store.ReadyExecution()
120		if err != nil {
121			return WorkFocusReport{}, fmt.Errorf("work focus: ready query: %w", err)
122		}
123		readyCount := len(readyBeads)
124		readySummary := WorkFocusReadySummary{
125			Count: readyCount,
126			Depth: workerReadyDepthLabel(readyCount),
127		}
128	
129		// Observe in_progress beads as a capacity signal.
130		inProgressBeads, err := store.List(bead.StatusInProgress, "", nil)
131		if err != nil {
132			return WorkFocusReport{}, fmt.Errorf("work focus: in_progress query: %w", err)
133		}
134		inProgressCount := len(inProgressBeads)
135	
136		// Conservative worker recommendation.
137		workerRec := buildWorkerRecommendation(readyCount, inProgressCount)
138	
139		// Unknowns: worker process liveness is not verifiable from the bead store.
140		var unknowns []string
141		if inProgressCount > 0 {
142			unknowns = append(unknowns, fmt.Sprintf(
143				"worker process liveness: %d bead(s) are in_progress but active worker process presence cannot be verified from the bead store",
144				inProgressCount,
145			))
146		}
147	
148		return WorkFocusReport{
149			HumanRequired:        humanRequired,
150			BlockedOrPlanning:    blockedOrPlanning,
151			ReadySummary:         readySummary,
152			WorkerRecommendation: workerRec,
153			Unknowns:             unknowns,
154		}, nil
155	}
156	
157	// buildWorkerRecommendation returns a conservative recommendation string.
158	// It suggests another worker only when ready depth is high and capacity is observable.
159	func buildWorkerRecommendation(readyCount, inProgressCount int) string {
160		switch {
161		case readyCount == 0:
162			return "Queue is empty; no worker action needed."
163		case inProgressCount > 0 && readyCount > 0:
164			return fmt.Sprintf(
165				"%d bead(s) ready; %d bead(s) currently claimed (in_progress). Monitor progress or run 'ddx work' to add capacity.",
166				readyCount, inProgressCount,
167			)
168		case readyCount >= 3:
169			return fmt.Sprintf(
170				"%d bead(s) ready and no active workers detected; consider running: ddx work",
171				readyCount,
172			)
173		default:
174			return fmt.Sprintf(
175				"%d bead(s) ready; run 'ddx work' to process.",
176				readyCount,
177			)
178		}
179	}
