181	func (f *CommandFactory) newWorkFocusCommand() *cobra.Command {
182		cmd := &cobra.Command{
183			Use:   "focus",
184			Short: "Show work requiring operator attention",
185			Long: `focus shows a read-only summary of queue items that require operator
186	attention — proposed beads, external blockers, dependency-waiting or
187	planning-required beads — along with a conservative worker-capacity
188	recommendation based on observable queue depth and in-progress signals.
189	
190	Unlike 'ddx work plan', focus is designed for interactive queue stewardship:
191	it surfaces the items workers will NOT pick up and recommends operator actions.
192	Worker-ready beads are not listed as primary intervention items; they appear
193	only as a depth summary.
194	
195	Use --json for machine-readable output with stable keys:
196	  human_required, blocked_or_planning, ready_summary,
197	  worker_recommendation, unknowns
198	`,
199			Example: `  # Show intervention queue in human-readable format
200	  ddx work focus
201	
202	  # Machine-readable output
203	  ddx work focus --json | jq '.human_required'`,
204			Args: cobra.NoArgs,
205			RunE: f.runWorkFocus,
206		}
207		cmd.Flags().Bool("json", false, "Output as JSON object with stable keys")
208		return cmd
209	}
210	
211	func (f *CommandFactory) runWorkFocus(cmd *cobra.Command, _ []string) error {
212		asJSON, _ := cmd.Flags().GetBool("json")
213	
214		ddxDir := f.WorkingDir + "/.ddx"
215		store := bead.NewStore(ddxDir)
216	
217		report, err := buildWorkFocusReport(store)
218		if err != nil {
219			return err
220		}
221	
222		if asJSON {
223			enc := json.NewEncoder(cmd.OutOrStdout())
224			enc.SetIndent("", "  ")
225			return enc.Encode(report)
226		}
227		return printWorkFocusText(cmd, report)
228	}
