230	func printWorkFocusText(cmd *cobra.Command, r WorkFocusReport) error {
231		out := cmd.OutOrStdout()
232	
233		// Section: Operator attention
234		fmt.Fprintf(out, "=== Operator attention (%d) ===\n", len(r.HumanRequired))
235		if len(r.HumanRequired) == 0 {
236			fmt.Fprintln(out, "  (none)")
237		} else {
238			for _, item := range r.HumanRequired {
239				fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
240				if item.Reason != "" {
241					fmt.Fprintf(out, "       reason: %s\n", item.Reason)
242				}
243				if item.SuggestedAction != "" {
244					fmt.Fprintf(out, "       suggested action: %s\n", item.SuggestedAction)
245				}
246			}
247		}
248	
249		// Section: Blocked / planning
250		fmt.Fprintf(out, "\n=== Blocked / planning (%d) ===\n", len(r.BlockedOrPlanning))
251		if len(r.BlockedOrPlanning) == 0 {
252			fmt.Fprintln(out, "  (none)")
253		} else {
254			for _, item := range r.BlockedOrPlanning {
255				fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
256				if item.Detail != "" {
257					fmt.Fprintf(out, "       blocker: %s — %s\n", item.BlockerKind, item.Detail)
258				} else {
259					fmt.Fprintf(out, "       blocker: %s\n", item.BlockerKind)
260				}
261			}
262		}
263	
264		// Section: Worker-ready summary
265		fmt.Fprintf(out, "\n=== Worker-ready summary ===\n")
266		fmt.Fprintf(out, "  %d bead(s) ready for worker execution (%s)\n", r.ReadySummary.Count, r.ReadySummary.Depth)
267	
268		// Section: Worker recommendation
269		fmt.Fprintf(out, "\n=== Worker recommendation ===\n")
270		fmt.Fprintf(out, "  %s\n", r.WorkerRecommendation)
271	
272		// Section: Unknowns
273		fmt.Fprintf(out, "\n=== Unknowns ===\n")
274		if len(r.Unknowns) == 0 {
275			fmt.Fprintln(out, "  (none)")
276		} else {
277			for _, u := range r.Unknowns {
278				fmt.Fprintf(out, "  - %s\n", u)
279			}
280		}
281	
282		return nil
283	}
