10	func (f *CommandFactory) newWorkClearCooldownsCommand() *cobra.Command {
11		cmd := &cobra.Command{
12			Use:   "clear-cooldowns",
13			Short: "Bulk-clear execute-loop cooldowns",
14			Long: `clear-cooldowns scans beads with an active execute-loop cooldown and clears
15	them in one pass. Use after a systemic issue (e.g., a push-layer failure) is
16	resolved so blocked beads re-enter the execution queue without per-bead --unset loops.
17	
18	Requires --all or --status to prevent accidental bulk clears.`,
19			Example: `  # Clear all active cooldowns
20	  ddx work clear-cooldowns --all
21	
22	  # Clear only push_failed cooldowns
23	  ddx work clear-cooldowns --status push_failed
24	
25	  # Preview without modifying state
26	  ddx work clear-cooldowns --all --dry-run`,
27			Args: cobra.NoArgs,
28			RunE: f.runWorkClearCooldowns,
29		}
30		cmd.Flags().Bool("all", false, "Clear cooldowns on every bead with execute-loop-retry-after set")
31		cmd.Flags().String("status", "", "Clear only beads where execute-loop-last-status matches this value")
32		cmd.Flags().Bool("dry-run", false, "Print what would be cleared without modifying state")
33		return cmd
34	}
35	
36	func (f *CommandFactory) runWorkClearCooldowns(cmd *cobra.Command, _ []string) error {
37		all, _ := cmd.Flags().GetBool("all")
38		status, _ := cmd.Flags().GetString("status")
39		dryRun, _ := cmd.Flags().GetBool("dry-run")
40	
41		if !all && status == "" {
42			return fmt.Errorf("requires --all or --status <value>")
43		}
44	
45		ddxDir := f.WorkingDir + "/.ddx"
46		store := bead.NewStore(ddxDir)
47	
48		var filter func(bead.Bead) bool
49		if status != "" {
50			s := status
51			filter = func(b bead.Bead) bool {
52				if b.Extra == nil {
53					return false
54				}
55				v, _ := b.Extra[bead.ExtraLastStatus].(string)
56				return v == s
57			}
58		}
59	
60		if dryRun {
61			allBeads, err := store.ReadAll()
62			if err != nil {
63				return err
64			}
65			count := 0
66			for _, b := range allBeads {
67				if b.Extra == nil {
68					continue
69				}
70				v, _ := b.Extra[bead.ExtraRetryAfter].(string)
71				if v == "" {
72					continue
73				}
74				if filter != nil && !filter(b) {
75					continue
76				}
77				count++
78			}
79			fmt.Fprintf(cmd.OutOrStdout(), "would clear %d cooldown(s)\n", count)
80			return nil
81		}
82	
83		count, err := store.ClearCooldowns(filter)
84		if err != nil {
85			return err
86		}
87		fmt.Fprintf(cmd.OutOrStdout(), "cleared %d cooldown(s)\n", count)
88		return nil
89	}
