package cmd

import (
	"encoding/csv"
	"encoding/json"
	"fmt"
	"math"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/attemptmetrics"
	"github.com/spf13/cobra"
)

// analyzeGroup accumulates raw per-row values for one dimension-key bucket.
type analyzeGroup struct {
	dimVals      []string
	count        int
	costs        []float64
	durations    []int
	inputToks    []int
	outputToks   []int
	successes    int
	reviewBlocks int
	escalated    int
}

// analyzeResult is one output row produced by "ddx work analyze".
type analyzeResult struct {
	Dims            map[string]string `json:"dims"`
	Count           int               `json:"count"`
	SuccessRate     float64           `json:"success_rate"`
	AvgCostUSD      float64           `json:"avg_cost_usd"`
	SumCostUSD      float64           `json:"sum_cost_usd"`
	P50DurationMS   float64           `json:"p50_duration_ms"`
	P95DurationMS   float64           `json:"p95_duration_ms"`
	AvgInputTokens  float64           `json:"avg_input_tokens"`
	AvgOutputTokens float64           `json:"avg_output_tokens"`
	ReviewBlockRate float64           `json:"review_block_rate"`
	EscalationRate  float64           `json:"escalation_rate"`
}

var analyzeValidDims = map[string]bool{
	"model": true, "harness": true, "profile": true,
	"prompt_template_hash": true, "spec_id": true, "outcome": true,
	"bead_id": true, "day": true, "week": true, "month": true,
}

var analyzeAggColumns = []string{
	"count", "success_rate", "avg_cost_usd", "sum_cost_usd",
	"p50_duration_ms", "p95_duration_ms",
	"avg_input_tokens", "avg_output_tokens",
	"review_block_rate", "escalation_rate",
}

func analyzeDimValue(row attemptmetrics.AttemptRow, dim string) string {
	switch dim {
	case "model":
		return row.Model
	case "harness":
		return row.Harness
	case "profile":
		return row.Profile
	case "prompt_template_hash":
		return row.PromptTemplateHash
	case "spec_id":
		return row.SpecID
	case "outcome":
		return row.Outcome
	case "bead_id":
		return row.BeadID
	case "day", "week", "month":
		if row.TSStart == "" {
			return ""
		}
		t, err := time.Parse(time.RFC3339, row.TSStart)
		if err != nil {
			return ""
		}
		switch dim {
		case "day":
			return t.UTC().Format("2006-01-02")
		case "week":
			year, week := t.UTC().ISOWeek()
			return fmt.Sprintf("%d-W%02d", year, week)
		case "month":
			return t.UTC().Format("2006-01")
		}
	}
	return ""
}

func analyzeParseSince(s string) (time.Duration, error) {
	if strings.HasSuffix(s, "d") {
		n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
		if err != nil || n <= 0 {
			return 0, fmt.Errorf("invalid --since value: %q", s)
		}
		return time.Duration(n) * 24 * time.Hour, nil
	}
	d, err := time.ParseDuration(s)
	if err != nil {
		return 0, fmt.Errorf("invalid --since value: %q: %w", s, err)
	}
	return d, nil
}

func analyzePercentile(sorted []int, p float64) float64 {
	n := len(sorted)
	if n == 0 {
		return 0
	}
	idx := p / 100.0 * float64(n-1)
	lo := int(math.Floor(idx))
	hi := int(math.Ceil(idx))
	if lo == hi {
		return float64(sorted[lo])
	}
	frac := idx - float64(lo)
	return float64(sorted[lo])*(1-frac) + float64(sorted[hi])*frac
}

func (f *CommandFactory) newWorkAnalyzeCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "analyze",
		Short: "Query cross-attempt performance metrics",
		Long: `analyze reads .ddx/metrics/attempts.jsonl and produces aggregated statistics
grouped by one or more dimensions.

Dimensions (--by):
  model, harness, profile, prompt_template_hash, spec_id, outcome, bead_id,
  day, week, month

Aggregations (always computed):
  count, success_rate, avg/sum cost_usd, p50/p95 duration_ms,
  avg input/output tokens, review_block_rate, escalation_rate
`,
		Example: `  # Performance by model
  ddx work analyze --by model

  # Composed dimensions
  ddx work analyze --by model,outcome

  # Recent week by spec
  ddx work analyze --by spec_id --since 7d

  # Drill into a specific model
  ddx work analyze --where model=claude-sonnet-4-6 --by prompt_template_hash

  # Machine-readable output
  ddx work analyze --by model --json
  ddx work analyze --by model --csv`,
		Args: cobra.NoArgs,
		RunE: f.runWorkAnalyze,
	}
	cmd.Flags().StringSlice("by", []string{"model"}, "Dimension(s) to group by (comma-separated or repeated)")
	cmd.Flags().String("since", "", "Only include attempts newer than this duration (e.g. 7d, 24h)")
	cmd.Flags().StringArray("where", nil, "Filter as key=value; multiple flags are ANDed")
	cmd.Flags().Bool("json", false, "Emit one JSON object per row (JSONL)")
	cmd.Flags().Bool("csv", false, "Emit CSV with header row")
	cmd.Flags().String("project", "", "Target project root (default: CWD git root)")
	return cmd
}

func (f *CommandFactory) runWorkAnalyze(cmd *cobra.Command, _ []string) error {
	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)

	rawDims, _ := cmd.Flags().GetStringSlice("by")
	sinceStr, _ := cmd.Flags().GetString("since")
	whereRaw, _ := cmd.Flags().GetStringArray("where")
	asJSON, _ := cmd.Flags().GetBool("json")
	asCSV, _ := cmd.Flags().GetBool("csv")

	// Validate and deduplicate dimensions.
	seen := map[string]bool{}
	var dims []string
	for _, d := range rawDims {
		d = strings.TrimSpace(d)
		if d == "" || seen[d] {
			continue
		}
		if !analyzeValidDims[d] {
			return fmt.Errorf("unknown dimension %q (valid: model harness profile prompt_template_hash spec_id outcome bead_id day week month)", d)
		}
		seen[d] = true
		dims = append(dims, d)
	}
	if len(dims) == 0 {
		dims = []string{"model"}
	}

	// Parse --since.
	var cutoff time.Time
	if sinceStr != "" {
		dur, err := analyzeParseSince(sinceStr)
		if err != nil {
			return err
		}
		cutoff = time.Now().Add(-dur)
	}

	// Parse --where.
	filters := make(map[string]string, len(whereRaw))
	for _, w := range whereRaw {
		parts := strings.SplitN(w, "=", 2)
		if len(parts) != 2 {
			return fmt.Errorf("--where must be key=value, got: %q", w)
		}
		filters[parts[0]] = parts[1]
	}

	// Load rows.
	rows, err := attemptmetrics.LoadRows(projectRoot)
	if err != nil {
		return fmt.Errorf("load attempts: %w", err)
	}

	// Group rows into buckets keyed by compound dimension value.
	groupMap := map[string]*analyzeGroup{}
	var keyOrder []string

	for _, row := range rows {
		// --since filter: skip rows older than cutoff; rows with no TSStart are included.
		if !cutoff.IsZero() && row.TSStart != "" {
			ts, perr := time.Parse(time.RFC3339, row.TSStart)
			if perr == nil && ts.Before(cutoff) {
				continue
			}
		}

		// --where filter: all predicates must match.
		skip := false
		for k, v := range filters {
			if analyzeDimValue(row, k) != v {
				skip = true
				break
			}
		}
		if skip {
			continue
		}

		// Build compound group key.
		vals := make([]string, len(dims))
		for i, d := range dims {
			vals[i] = analyzeDimValue(row, d)
		}
		key := strings.Join(vals, "\x00")

		g, ok := groupMap[key]
		if !ok {
			g = &analyzeGroup{dimVals: vals}
			groupMap[key] = g
			keyOrder = append(keyOrder, key)
		}

		g.count++
		g.costs = append(g.costs, row.CostUSD)
		g.durations = append(g.durations, row.DurationMS)
		g.inputToks = append(g.inputToks, row.InputTokens)
		g.outputToks = append(g.outputToks, row.OutputTokens)
		if row.Outcome == "closed-merged" {
			g.successes++
		}
		if row.ReviewVerdict == "block" {
			g.reviewBlocks++
		}
		if row.LadderStepsTaken > 0 {
			g.escalated++
		}
	}

	// Sort for deterministic output.
	sort.Strings(keyOrder)

	// Build result rows.
	results := make([]analyzeResult, 0, len(keyOrder))
	for _, key := range keyOrder {
		g := groupMap[key]

		dimMap := make(map[string]string, len(dims))
		for i, d := range dims {
			dimMap[d] = g.dimVals[i]
		}

		var sumCost float64
		for _, c := range g.costs {
			sumCost += c
		}
		avgCost := 0.0
		if g.count > 0 {
			avgCost = sumCost / float64(g.count)
		}

		sortedDur := make([]int, len(g.durations))
		copy(sortedDur, g.durations)
		sort.Ints(sortedDur)

		var sumIn, sumOut int
		for i := range g.inputToks {
			sumIn += g.inputToks[i]
			sumOut += g.outputToks[i]
		}
		avgIn, avgOut := 0.0, 0.0
		if g.count > 0 {
			avgIn = float64(sumIn) / float64(g.count)
			avgOut = float64(sumOut) / float64(g.count)
		}

		rate := func(n int) float64 {
			if g.count == 0 {
				return 0
			}
			return float64(n) / float64(g.count)
		}

		results = append(results, analyzeResult{
			Dims:            dimMap,
			Count:           g.count,
			SuccessRate:     rate(g.successes),
			AvgCostUSD:      avgCost,
			SumCostUSD:      sumCost,
			P50DurationMS:   analyzePercentile(sortedDur, 50),
			P95DurationMS:   analyzePercentile(sortedDur, 95),
			AvgInputTokens:  avgIn,
			AvgOutputTokens: avgOut,
			ReviewBlockRate: rate(g.reviewBlocks),
			EscalationRate:  rate(g.escalated),
		})
	}

	if asJSON {
		return analyzeWriteJSON(cmd, results)
	}
	if asCSV {
		return analyzeWriteCSV(cmd, dims, results)
	}
	return analyzeWriteTable(cmd, dims, results)
}

func analyzeFormatValues(r analyzeResult) []string {
	return []string{
		strconv.Itoa(r.Count),
		fmt.Sprintf("%.3f", r.SuccessRate),
		fmt.Sprintf("%.4f", r.AvgCostUSD),
		fmt.Sprintf("%.4f", r.SumCostUSD),
		fmt.Sprintf("%.0f", r.P50DurationMS),
		fmt.Sprintf("%.0f", r.P95DurationMS),
		fmt.Sprintf("%.1f", r.AvgInputTokens),
		fmt.Sprintf("%.1f", r.AvgOutputTokens),
		fmt.Sprintf("%.3f", r.ReviewBlockRate),
		fmt.Sprintf("%.3f", r.EscalationRate),
	}
}

func analyzeWriteJSON(cmd *cobra.Command, results []analyzeResult) error {
	enc := json.NewEncoder(cmd.OutOrStdout())
	for _, r := range results {
		if err := enc.Encode(r); err != nil {
			return err
		}
	}
	return nil
}

func analyzeWriteCSV(cmd *cobra.Command, dims []string, results []analyzeResult) error {
	w := csv.NewWriter(cmd.OutOrStdout())
	header := make([]string, 0, len(dims)+len(analyzeAggColumns))
	header = append(header, dims...)
	header = append(header, analyzeAggColumns...)
	if err := w.Write(header); err != nil {
		return err
	}
	for _, r := range results {
		row := make([]string, 0, len(dims)+len(analyzeAggColumns))
		for _, d := range dims {
			row = append(row, r.Dims[d])
		}
		row = append(row, analyzeFormatValues(r)...)
		if err := w.Write(row); err != nil {
			return err
		}
	}
	w.Flush()
	return w.Error()
}

func analyzeWriteTable(cmd *cobra.Command, dims []string, results []analyzeResult) error {
	out := cmd.OutOrStdout()
	if len(results) == 0 {
		fmt.Fprintln(out, "(no data)")
		return nil
	}

	headers := make([]string, 0, len(dims)+len(analyzeAggColumns))
	headers = append(headers, dims...)
	headers = append(headers, analyzeAggColumns...)

	widths := make([]int, len(headers))
	for i, h := range headers {
		widths[i] = len(h)
	}

	allVals := make([][]string, len(results))
	for ri, r := range results {
		row := make([]string, 0, len(headers))
		for _, d := range dims {
			row = append(row, r.Dims[d])
		}
		row = append(row, analyzeFormatValues(r)...)
		allVals[ri] = row
		for i, v := range row {
			if len(v) > widths[i] {
				widths[i] = len(v)
			}
		}
	}

	// Header row.
	for i, h := range headers {
		if i > 0 {
			fmt.Fprint(out, "  ")
		}
		fmt.Fprintf(out, "%-*s", widths[i], h)
	}
	fmt.Fprintln(out)

	// Separator.
	for i, w := range widths {
		if i > 0 {
			fmt.Fprint(out, "  ")
		}
		fmt.Fprint(out, strings.Repeat("-", w))
	}
	fmt.Fprintln(out)

	// Data rows.
	for _, row := range allVals {
		for i, v := range row {
			if i > 0 {
				fmt.Fprint(out, "  ")
			}
			fmt.Fprintf(out, "%-*s", widths[i], v)
		}
		fmt.Fprintln(out)
	}

	return nil
}

